        ['Puerto Morelos (Ventana al Mar)', [20.8475, -86.8753]],
        ['Ruta de los Cenotes', [20.8522, -86.8975]],
        ['Leona Vicario', [20.9950, -87.1992]],
        ['Valladolid Nuevo', [21.0289, -87.4117]],
        ['Agua Holbox', [21.5239, -87.3822]],
        ['Chiquilá', [21.4361, -87.2650]],
        ['Kantunilkín', [21.0950, -87.4983]],
        ['El Ideal', [21.0428, -87.5681]],
        ['Ignacio Zaragoza (KM 80)', [21.0028, -87.6742]],
        ['Cristóbal Colón', [20.9572, -87.8094]],
        ['Piste', [20.6975, -88.5833]],
        ['Chichén Itzá', [20.6843, -88.5678]],
        ['Mérida (Centro)', [20.9674, -89.6236]],
        ['Ruta 44 / La Joya', [21.1606, -86.8306]],
        ['Ruta 4 / Mercado 28', [21.1606, -86.8306]],
    ]);

    let finder: CoordinateFinder;

    beforeEach(() => {
        finder = new CoordinateFinder(mockDb);
    });

    describe('find', () => {
        it('should return exact match', () => {
            const coords = finder.find('Plaza Las Américas');
            expect(coords).toEqual([21.1619, -86.8249]);
        });

        it('should be case insensitive', () => {
            const coords = finder.find('plaza las amÉricas');
            expect(coords).toEqual([21.1619, -86.8249]);
        });

        it('should handle token matching', () => {
             const coords = finder.find('Américas Plaza');
             expect(coords).toEqual([21.1619, -86.8249]);
        });

        it('should handle partial words (fuzzy search)', () => {
             const coords = finder.find('Delfines');
             expect(coords).toEqual([21.0592, -86.7797]);
        });

        it('should return null for non-existent stop', () => {
            const coords = finder.find('Non-Existent Stop');
            expect(coords).toBeNull();
        });

        it('should handle empty string', () => {
            const coords = finder.find('');
            expect(coords).toBeNull();
        });

        it('should populate the cache on fuzzy match and return from cache on repeat call', () => {
            // 'Américas Plaza' is not an exact key, so it goes through fuzzy search
            const query = 'Américas Plaza';
            expect((finder as any).cache.has(query)).toBe(false);

            const result1 = finder.find(query);
            expect(result1).toEqual([21.1619, -86.8249]);

            // Cache should now contain the result
            expect((finder as any).cache.has(query)).toBe(true);

            // Second call should return the same result (served from cache)
            const result2 = finder.find(query);
            expect(result2).toEqual([21.1619, -86.8249]);
        });
    });

    describe('findBestMatch', () => {
         it('should return exact match with name', () => {
             const match = finder.findBestMatch('Plaza Las Américas');
             expect(match).toEqual({ name: 'Plaza Las Américas', coords: [21.1619, -86.8249] });
         });
    });

    describe('search', () => {
        it('should return exact matches first', () => {
            const results = finder.search('Plaza Las Américas');
            expect(results[0].name).toBe('Plaza Las Américas');
        });

        it('should return results that start with the query next', () => {
            const results = finder.search('Plaza');
            // 'Plaza' should match 'Plaza Outlet', 'Plaza Héroes', 'Plaza Las Américas', etc.
            // All of them start with 'Plaza' so they should come before 'Gran Plaza'
            const firstResultIndex = results.findIndex(r => r.name.startsWith('Plaza'));
            const granPlazaIndex = results.findIndex(r => r.name === 'Gran Plaza');

            // Limit is 5 by default, so Gran Plaza might not even be in the results
            if (granPlazaIndex !== -1) {
                expect(firstResultIndex).toBeLessThan(granPlazaIndex);
            }
            expect(firstResultIndex).toBe(0); // The first result should start with Plaza
        });

        it('should return results based on length', () => {
            const results = finder.search('Ruta 4');
            // Both 'Ruta 4 / Mercado 28' and 'Ruta 44 / La Joya' start with 'ruta 4'
            // When startsWith is tied, the shorter name comes first
            // 'Ruta 44 / La Joya' (17 chars) is shorter than 'Ruta 4 / Mercado 28' (19 chars)
            const ruta44Index = results.findIndex(r => r.name === 'Ruta 44 / La Joya');
            const ruta4Index = results.findIndex(r => r.name === 'Ruta 4 / Mercado 28');

            expect(ruta44Index).not.toBe(-1);
            expect(ruta4Index).not.toBe(-1);

            // Shorter name should rank higher
            expect(ruta44Index).toBeLessThan(ruta4Index);
        });

        it('should handle Direct Substring Fallback for short queries', () => {
            // Direct substring check — bypasses token index for short/partial queries
            // The token index requires tokens >= 3 length. So searching for "km"
            // relies entirely on the direct substring check.
            const results = finder.search('km');
            expect(results.length).toBeGreaterThan(0);
            expect(results.some(r => r.name.toLowerCase().includes('km'))).toBe(true);
        });

        it('should respect the limit parameter', () => {
            const results = finder.search('Plaza', 3);
            expect(results.length).toBe(3);
        });

        it('should handle empty query', () => {
            const results = finder.search('');
            expect(results).toEqual([]);
        });

        it('should handle very short queries that do not match direct substring', () => {
            const results = finder.search('z'); // Length < 2 should return [] according to the code
            expect(results).toEqual([]);
        });

        it('should handle Spanish accents in query', () => {
            const results = finder.search('Américas');
            expect(results.length).toBeGreaterThan(0);
            expect(results[0].name).toBe('Plaza Las Américas');
        });
    });

    describe('uninitialized state', () => {
        it('should not throw if db is empty and searches are made', () => {
             const emptyFinder = new CoordinateFinder(new Map());
             expect(emptyFinder.find('Plaza Las Américas')).toBeNull();
             expect(emptyFinder.findBestMatch('Plaza Las Américas')).toBeNull();
             expect(emptyFinder.search('Plaza Las Américas')).toEqual([]);
        });    });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { CoordinatesStore } from '../utils/CoordinatesStore';

// Mock fetch
const mockFetch = vi.fn();
global.fetch = mockFetch;

describe('CoordinatesStore', () => {
    let store: CoordinatesStore;

    beforeEach(() => {
        // Create a fresh instance for each test
        store = new CoordinatesStore();
        // Reset the static singleton for isolation
        (CoordinatesStore as any).instance = store;
        (store as any).loadingPromise = null;
        (store as any).db = null;
        mockFetch.mockReset();
    });

    it('should be a singleton via static instance', () => {
        const store2 = CoordinatesStore.instance;
        expect(store2).toBe(store);
    });

    it('should initialize with injected data', async () => {
        const mockData = {
            version: '1.0',
            rutas: [
                {
                    id: 'R1',
                    nombre: 'Ruta 1',
                    tarifa: 10,
                    tipo: 'Bus',
                    paradas: [
                        { nombre: 'Stop A', lat: 10, lng: 10, orden: 1 }
                    ]
                }
            ]
        };

        const result = await store.init(mockData);
        expect(result.data).toEqual(mockData);
        // utils/CoordinatesStore stores as [lat, lng] tuples with lowercase keys
        expect(store.getDB()!.get('stop a')).toEqual([10, 10]);
    });

    it('should fetch data if not injected', async () => {
        const mockData = {
            version: '1.0',
            rutas: [
                {
                    id: 'R1',
                    nombre: 'Ruta 1',
                    tarifa: 10,
                    tipo: 'Bus',
                    paradas: [
                        { nombre: 'Stop B', lat: 20, lng: 20, orden: 1 }
                    ]
                }
            ]
        };

        mockFetch.mockResolvedValue({
            ok: true,
            text: async () => JSON.stringify(mockData)
        });

        const result = await store.init();
        expect(result.data).toEqual(mockData);
        expect(store.getDB()!.get('stop b')).toEqual([20, 20]);
        expect(mockFetch).toHaveBeenCalledWith('/data/master_routes.optimized.json');
    });

    it('should find nearest stop', async () => {
        const mockData = {
            version: '1.0',
            rutas: [
                {
                    id: 'R1',
                    nombre: 'Ruta 1',
                    tarifa: 10,
                    tipo: 'Bus',
                    paradas: [
                        { nombre: 'Stop Close', lat: 10, lng: 10, orden: 1 },
                        { nombre: 'Stop Far', lat: 50, lng: 50, orden: 2 }
                    ]
                }
            ]
        };

        await store.init(mockData);

        // Point close to 10,10 (within SpatialHash grid of ~1km)
        const nearest = store.findNearest(10.005, 10.005);
        expect(nearest).toBe('stop close');
    });

    it('should return correct nearest when spatial index has candidates in same cell', async () => {
        // Two stops very close together (same spatial hash cell, ~0.001 deg apart)
        const mockData = {
            version: '1.0',
            rutas: [
                {
                    id: 'R1',
                    nombre: 'Ruta 1',
                    tarifa: 10,
                    tipo: 'Bus',
                    paradas: [
                        { nombre: 'Stop Near', lat: 10.001, lng: 10.001, orden: 1 },
                        { nombre: 'Stop Nearer', lat: 10.0005, lng: 10.0005, orden: 2 }
                    ]
                }
            ]
        };

        await store.init(mockData);

        // Query point exactly at 10,10 — "Stop Nearer" is closer
        const nearest = store.findNearest(10.0, 10.0);
        expect(nearest).toBe('stop nearer');
    });

    it('should return correct nearest when candidate is in a neighboring cell', async () => {
        // Place one stop just across a cell boundary from the query point
        // Cell size is 0.01 deg. Query at 10.0, nearest stop at 10.009 (same or adjacent cell)
        // and a farther stop in a different cell
        const mockData = {
            version: '1.0',
            rutas: [
                {
                    id: 'R1',
                    nombre: 'Ruta 1',
                    tarifa: 10,
                    tipo: 'Bus',
                    paradas: [
                        { nombre: 'Adjacent Cell Stop', lat: 10.009, lng: 10.009, orden: 1 },
                        { nombre: 'Far Stop', lat: 20.0, lng: 20.0, orden: 2 }
                    ]
                }
            ]
        };

        await store.init(mockData);

        const nearest = store.findNearest(10.0, 10.0);
        expect(nearest).toBe('adjacent cell stop');
    });

    it('should return correct nearest when no stops are in spatial index neighborhood', async () => {
        // All stops are far from query point — spatial index query returns no candidates
        // Global fallback must find the correct nearest
        const mockData = {
            version: '1.0',
            rutas: [
                {
                    id: 'R1',
                    nombre: 'Ruta 1',
                    tarifa: 10,
                    tipo: 'Bus',
                    paradas: [
                        { nombre: 'Distant Stop A', lat: 80.0, lng: 80.0, orden: 1 },
                        { nombre: 'Distant Stop B', lat: 85.0, lng: 85.0, orden: 2 }
                    ]
                }
            ]
        };

        await store.init(mockData);

        // Query at 0,0 — neither stop is in the spatial index's 3x3 neighborhood
        // Global fallback should find "Distant Stop A" as nearer
        const nearest = store.findNearest(0.0, 0.0);
        expect(nearest).toBe('distant stop a');
    });
});

describe('CoordinatesStore.findNearest - spatial index fast path', () => {
    let store: CoordinatesStore;

    // Helper to build minimal route data from a list of stops
    const makeData = (stops: Array<{ nombre: string; lat: number; lng: number }>) => ({
        version: '1.0',
        rutas: [{
            id: 'R1',
            nombre: 'Ruta 1',
            tarifa: 15,
            tipo: 'Bus',
            paradas: stops.map((s, i) => ({ ...s, orden: i + 1 }))
        }]
    });

    beforeEach(() => {
        store = new CoordinatesStore();
        (CoordinatesStore as any).instance = store;
        (store as any).loadingPromise = null;
        (store as any).db = null;
    });

    // All tests use coordinates near (10.0, 10.0).
    // Default cell size = 0.01 deg (~1.11 km at equator).
    // Cell for (10.0, 10.0): x=1000, y=1000.

    it('finds nearest stop via spatial index when stop is in the same cell as the query point', async () => {
        // Stop at (10.005, 10.0) is in cell y=1000 (same as query at 10.0, 10.0).
        // Haversine distance ≈ 0.556 km < 1.0 km → early-return triggers.
        await store.init(makeData([
            { nombre: 'Stop Same Cell', lat: 10.005, lng: 10.0 },
            { nombre: 'Stop Far Away', lat: 30.0, lng: 30.0 },
        ]));
        const nearest = store.findNearest(10.0, 10.0);
        expect(nearest).toBe('stop same cell');
    });

    it('finds nearest stop via spatial index when stop is in a neighboring cell', async () => {
        // Stop at (9.995, 10.0) is in cell y=999 — a direct south neighbor of query cell y=1000.
        // Haversine distance ≈ 0.556 km < 1.0 km → early-return triggers.
        await store.init(makeData([
            { nombre: 'Stop Neighbor Cell', lat: 9.995, lng: 10.0 },
            { nombre: 'Stop Far Away', lat: 30.0, lng: 30.0 },
        ]));
        const nearest = store.findNearest(10.0, 10.0);
        expect(nearest).toBe('stop neighbor cell');
    });

    it('returns the closest stop when multiple candidates are returned by the spatial index', async () => {
        // Both stops are in the same cell (y=1000); Stop Near is 0.222 km away, Stop Mid is 0.666 km away.
        await store.init(makeData([
            { nombre: 'Stop Near', lat: 10.002, lng: 10.0 },
            { nombre: 'Stop Mid',  lat: 10.006, lng: 10.0 },
        ]));
        const nearest = store.findNearest(10.0, 10.0);
        expect(nearest).toBe('stop near');
    });

    it('invokes spatialIndex.query and returns a non-empty candidate list on a spatial-index hit', async () => {
        await store.init(makeData([
            { nombre: 'Stop Alpha', lat: 10.005, lng: 10.0 },
        ]));

        const spatialIndex = (store as any).spatialIndex;
        const querySpy = vi.spyOn(spatialIndex, 'query');

        const nearest = store.findNearest(10.0, 10.0);

        expect(nearest).toBe('stop alpha');
        expect(querySpy).toHaveBeenCalledOnce();
        // Verify the spatial index actually returned candidates (fast path was exercised)
        const candidates = querySpy.mock.results[0].value as unknown[];
        expect(candidates.length).toBeGreaterThan(0);
    });

    it('falls back to global scan when all spatial-index candidates exceed the 1 km early-return threshold', async () => {
        // Stop at (10.011, 10.0) is in neighboring cell y=1001.
        // Haversine distance ≈ 1.22 km > 1.0 km → no early-return; global scan is used to confirm.
        await store.init(makeData([
            { nombre: 'Stop Beyond Threshold', lat: 10.011, lng: 10.0 },
        ]));
        const nearest = store.findNearest(10.0, 10.0);
        expect(nearest).toBe('stop beyond threshold');
    });
});

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { drawRoute, RouteData } from '../utils/RouteDrawer';

// Mock map
const mockMap = {
    fitBounds: vi.fn()
};

// Mock layers
const mockLayerGroupInstance = {
    clearLayers: vi.fn(),
    remove: vi.fn(),
    addTo: vi.fn().mockReturnThis()
};

const mockPolyline = {
    addTo: vi.fn().mockReturnThis()
};

const mockMarker = {
    bindPopup: vi.fn().mockReturnThis(),
    addTo: vi.fn().mockReturnThis()
};

const mockCircleMarker = {
    bindPopup: vi.fn().mockReturnThis(),
    addTo: vi.fn().mockReturnThis()
};

// Mock L
const mockL = {
    layerGroup: vi.fn(() => mockLayerGroupInstance),
    polyline: vi.fn(() => mockPolyline),
    marker: vi.fn(() => mockMarker),
    circleMarker: vi.fn(() => mockCircleMarker)
};

describe('RouteDrawer', () => {
    beforeEach(() => {
        vi.stubGlobal('window', { L: mockL });
        vi.clearAllMocks();

        // Setup default mock returns
        mockLayerGroupInstance.addTo.mockReturnValue(mockLayerGroupInstance);
        mockPolyline.addTo.mockReturnValue(mockPolyline);
        mockMarker.bindPopup.mockReturnValue(mockMarker);
        mockCircleMarker.bindPopup.mockReturnValue(mockCircleMarker);
        mockMarker.addTo.mockReturnValue(mockMarker);
        mockCircleMarker.addTo.mockReturnValue(mockCircleMarker);
    });

    afterEach(() => {
        vi.unstubAllGlobals();
    });

    it('should return undefined if L is not available', () => {
        vi.stubGlobal('window', {}); // No L
        const result = drawRoute(mockMap as any, {}, null, {});
        expect(result).toBeUndefined();
    });

    it('should return undefined if map is not available', () => {
        const result = drawRoute(null as any, {}, null, {});
        expect(result).toBeUndefined();
    });

    it('should clear and remove existing layer group if provided', () => {
        const existingLayerGroup = {
            clearLayers: vi.fn(),
            remove: vi.fn(),
            addTo: vi.fn()
        };
        drawRoute(mockMap as any, { paradas: [{lat: 1, lng: 1}] }, existingLayerGroup as any, {});
        expect(existingLayerGroup.clearLayers).toHaveBeenCalled();
        expect(existingLayerGroup.remove).toHaveBeenCalled();
    });

    it('should return undefined if data structure is invalid (missing legs, paradas, stops)', () => {
        const result = drawRoute(mockMap as any, {}, null, {});
        expect(result).toBeUndefined();
    });

    it('should draw a route with new format (paradas objects)', () => {
        const routeData: RouteData = {
            paradas: [
                { lat: 21.1619, lng: -86.8515, name: 'Start' },
                { lat: 21.1620, lon: -86.8520, name: 'Middle' }, // using lon
                { lat: '21.1621', lng: '-86.8525', name: 'End' } // string values
            ]
        };

        const result = drawRoute(mockMap as any, routeData, null, {});

        expect(result).toBe(mockLayerGroupInstance);
        expect(mockL.layerGroup).toHaveBeenCalled();
        expect(mockLayerGroupInstance.addTo).toHaveBeenCalledWith(mockMap);

        // Polyline should be created
        expect(mockL.polyline).toHaveBeenCalledWith(
            [
                [21.1619, -86.8515],
                [21.162, -86.852],
                [21.1621, -86.8525]
            ],
            { color: '#F97316', weight: 4, opacity: 0.8, dashArray: null }
        );

        // Map bounds should be fitted
        expect(mockMap.fitBounds).toHaveBeenCalledWith(
            [
                [21.1619, -86.8515],
                [21.162, -86.852],
                [21.1621, -86.8525]
            ],
            { padding: [50, 50] }
        );

        // Start and end markers should be created
        expect(mockL.marker).toHaveBeenCalledTimes(2); // Start and End
        expect(mockMarker.bindPopup).toHaveBeenCalledWith('<b>Inicio:</b> Start');
        expect(mockMarker.bindPopup).toHaveBeenCalledWith('<b>Fin:</b> End');

        // Middle circle marker should be created
        expect(mockL.circleMarker).toHaveBeenCalledTimes(1); // Middle stop
        expect(mockCircleMarker.bindPopup).toHaveBeenCalledWith('Middle');

        // Markers should be added to layer group
        expect(mockMarker.addTo).toHaveBeenCalledWith(mockLayerGroupInstance);
        expect(mockCircleMarker.addTo).toHaveBeenCalledWith(mockLayerGroupInstance);
    });

    it('should draw a route with legacy format (stops array of strings)', () => {
        const routeData: RouteData = {
            stops: ['Stop1', 'Stop2']
        };
        const coordinatesDB = new Map<string, [number, number]>([
            ['Stop1', [21.0, -86.0]],
            ['Stop2', [21.1, -86.1]]
        ]);

        drawRoute(mockMap as any, routeData, null, coordinatesDB);

        expect(mockL.polyline).toHaveBeenCalledWith(
            [[21.0, -86.0], [21.1, -86.1]],
            expect.any(Object)
        );
        expect(mockL.marker).toHaveBeenCalledTimes(2);
    });

    it('should draw a route with multiple legs', () => {
        const routeData: RouteData = {
            legs: [
                {
                    paradas: [
                        { lat: 1, lng: 1, name: 'A' },
                        { lat: 2, lng: 2, name: 'B' }
                    ]
                },
                {
                    stops_info: [
                        { lat: 2, lng: 2, name: 'B' },
                        { lat: 3, lng: 3, name: 'C' }
                    ]
                }
            ]
        };

        drawRoute(mockMap as any, routeData, null, {});

        // 2 Polylines (one for each leg)
        expect(mockL.polyline).toHaveBeenCalledTimes(2);

        // Leg 1 polyline
        expect(mockL.polyline).toHaveBeenNthCalledWith(1,
            [[1, 1], [2, 2]],
            expect.objectContaining({ color: '#F97316', dashArray: null })
        );

        // Leg 2 polyline
        expect(mockL.polyline).toHaveBeenNthCalledWith(2,
            [[2, 2], [3, 3]],
            expect.objectContaining({ color: '#0EA5E9', dashArray: '10, 10' })
        );

        // Markers: Start(A), Transfer(B), End(C)
        expect(mockL.marker).toHaveBeenCalledTimes(3);
        expect(mockMarker.bindPopup).toHaveBeenCalledWith('<b>Inicio:</b> A');
        expect(mockMarker.bindPopup).toHaveBeenCalledWith('<b>Transbordo:</b> B');
