import { getDistance } from "./utils";
import { SpatialHash } from "./SpatialHash";

// Define Types
type Coordinate = { name: string; lat: number; lng: number };

type RouteData = {
    id: string;
    nombre: string;
    paradas: {
        lat: number;
        lng: number;
        nombre: string;
    }[];
};

export class CoordinatesStore {
    // 🛡️ SECURITY FIX (Prototype Pollution Prevention)
    // By using a Map instead of a plain Object (Record<string, ...>),
    // we prevent attacks where malicious JSON payload keys like "__proto__"
    // or "constructor" could overwrite JS prototype chain methods,
    // potentially leading to DoS or bypassing logic checks.
    private db: Map<string, [number, number]> | null = null;
    private spatialIndex: SpatialHash<string> | null = null;
    private loadingPromise: Promise<{ text: string, data: any }> | null = null;
    private allPoints: Coordinate[] = [];

    static instance = new CoordinatesStore();

    async init(initialData?: any): Promise<{ text: string, data: any }> {
        if (this.loadingPromise && !initialData) return this.loadingPromise;

        this.loadingPromise = (async () => {
            try {
                let data = initialData;
                let text = "";

                if (data) {
                    console.log("[CoordinatesStore] ⚡ Using injected data (Skipped Fetch)");
                    text = JSON.stringify(data);
                } else {
                    console.log("[CoordinatesStore] 🌍 Fetching master routes for coordinates...");
                    try {
                        const res = await fetch('/data/master_routes.optimized.json');
                        if (res.ok) {
                            text = await res.text();
                            console.log("[CoordinatesStore] ⚡ Loaded optimized catalog");
                        } else {
                            throw new Error("Optimized not found");
                        }
                    } catch (e) {
                        console.warn("[CoordinatesStore] Optimized catalog missing, falling back...", e);
                        const res = await fetch('/data/master_routes.json');
                        if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`);
                        text = await res.text();
                    }
                    data = JSON.parse(text);
                }

                this.db = new Map<string, [number, number]>();
                this.spatialIndex = new SpatialHash<string>(); // Initialize SpatialHash
                this.allPoints = []; // Clear on re-init to prevent duplicates

                if (data.rutas) {
                    data.rutas.forEach((route: RouteData) => {
                        route.paradas.forEach(stop => {
                            // Normalize Key
                            const key = stop.nombre.toLowerCase().trim();
                            if (this.db) this.db.set(key, [stop.lat, stop.lng]);
                        });
                    });
                }
                // Populate Spatial Index and List
                if (this.db) {
                    for (const [name, coords] of this.db.entries()) {
                         const lat = coords[0];
                         const lng = coords[1];
                         if (this.spatialIndex) this.spatialIndex.insert(lat, lng, name);
                         this.allPoints.push({ name, lat, lng });
                    }
                }
                console.log(`[CoordinatesStore] Indexed ${this.db?.size || 0} stops.`);
                return { text, data };
            } catch (e) {
                console.error("[CoordinatesStore] Failed to load data", e);
                return { text: "{}", data: {} };
            }
        })();

        return this.loadingPromise;
    }

    getCoordinates(stopName: string) {
        if (!this.db) return null;
        const key = stopName.toLowerCase().trim();
        return this.db.get(key) || null;
    }

    getDB() {
        return this.db;
    }

    findNearest(lat: number, lng: number): string | null {
        if (!this.db) return null;

        let minDist = Infinity;
        let nearest: string | null = null;

        // Try O(1) Spatial Hash first
        if (this.spatialIndex) {
            const candidates = this.spatialIndex.query(lat, lng);
            if (candidates.length > 0) {
                for (const point of candidates) {
                    const d = getDistance(lat, lng, point.lat, point.lng);
                    if (d < minDist) {
                        minDist = d;
                        nearest = point.data;
                    }
                }
            }
        }

        // 2. Global Search (O(N)) - Verifies against all points using minDist from spatial index
        // Using array iteration is faster than Object.entries
        for (const point of this.allPoints) {
            const d = getDistance(lat, lng, point.lat, point.lng);
            if (d < minDist) {
                minDist = d;
                nearest = point.name;
            }
        }

        return nearest;
    }
}

export const coordinatesStore = CoordinatesStore.instance;

import { escapeHtml } from './utils';

// --- Minimal Leaflet Types ---
// Defined locally to avoid adding @types/leaflet dependency

interface LatLngExpression extends Array<number> {
    0: number;
    1: number;
}

interface Map {
    fitBounds(bounds: any[], options?: any): void;
}

interface LayerGroup {
    clearLayers(): void;
    remove(): void;
    addTo(map: Map): LayerGroup;
}

interface PolylineOptions {
    color: string;
    weight: number;
    opacity: number;
    dashArray?: string | null;
}

interface MarkerOptions {
    icon?: any;
    radius?: number;
    color?: string;
    fillOpacity?: number;
}

// --- Data Types ---

interface RouteStop {
    lat?: number | string;
    lng?: number | string;
    lon?: number | string;
    nombre?: string;
    name?: string;
}

export interface RouteData {
    legs?: {
        paradas?: RouteStop[];
        stops_info?: RouteStop[];
        stops?: string[];
        name?: string;
        nombre?: string;
    }[];
    paradas?: RouteStop[];
    stops?: string[];
    nombre?: string;
    name?: string;
}

// --- Internal Helpers ---

function createPolyline(L: any, coords: LatLngExpression[], options: PolylineOptions): any {
    return L.polyline(coords, options);
}

function createMarker(L: any, coords: LatLngExpression, popupContent: string, options?: MarkerOptions): any {
    const marker = options && options.radius
        ? L.circleMarker(coords, options)
        : L.marker(coords, options);
    return marker.bindPopup(popupContent);
}

// --- Main Export ---

/**
 * Draws a route on the map, handling multiple legs, transfers, and legacy data formats.
 *
 * @param map The Leaflet map instance.
 * @param data The route data to draw.
 * @param existingLayerGroup The existing layer group to clear (if any).
 * @param coordinatesDB The coordinates database for legacy routes (stop names -> coords).
 * @returns The new LayerGroup containing the drawn route.
 */
export function drawRoute(
    map: Map,
    data: RouteData,
    existingLayerGroup: LayerGroup | null | undefined,
    coordinatesDB: Map<string, [number, number]>
): LayerGroup | undefined {

    // Access global L safely
    const L = (window as any).L;
    if (!L || !map) return undefined;

    // Reset layers
    if (existingLayerGroup) {
        existingLayerGroup.clearLayers();
        existingLayerGroup.remove();
    }
    const layerGroup = L.layerGroup().addTo(map);

    // Normalize Data Structure
    // 'data' could be a full Journey (with legs) or a single Route object
    let legs: any[] = [];
    if (data.legs && Array.isArray(data.legs)) {
        legs = data.legs;
    } else if (data.paradas && Array.isArray(data.paradas)) {
        // Single route treated as one leg
        legs = [{ paradas: data.paradas, name: data.nombre || data.name }];
    } else if (data.stops && Array.isArray(data.stops)) {
        // Legacy format
        legs = [{ stops: data.stops, name: data.nombre || data.name }];
    } else {
        return undefined; // Invalid data
    }

    const allBounds: LatLngExpression[] = [];
    const newLayers: any[] = []; // Array to collect all markers before adding to layerGroup

    legs.forEach((leg, index) => {
        const routeCoords: LatLngExpression[] = [];
        const validStops: { name: string, latlng: LatLngExpression }[] = [];

        // Try to get explicit coordinates from 'paradas' object array
        const stopsSource = leg.paradas || leg.stops_info || [];

        if (stopsSource.length > 0 && typeof stopsSource[0] === 'object') {
            // New Format: [{ lat, lng, nombre }, ...]
            stopsSource.forEach((stop: RouteStop) => {
                if (stop.lat && (stop.lng !== undefined || stop.lon !== undefined)) {
                    const lat = parseFloat(String(stop.lat));
                    const lngRaw = stop.lng !== undefined ? stop.lng : stop.lon;
                    const lng = parseFloat(String(lngRaw));

                    // Check logic:
                    // Sometimes JSON has "lon" instead of "lng"

                    if (!isNaN(lat) && !isNaN(lng)) {
                        const coords: LatLngExpression = [lat, lng];
                        routeCoords.push(coords);
                        validStops.push({ name: stop.nombre || stop.name || 'Parada', latlng: coords });
                        allBounds.push(coords);
                    }
                }
            });
        } else {
            // Legacy: Array of strings + coordinatesDB
            const stopNames: string[] = leg.stops || [];
            stopNames.forEach(name => {
                if (coordinatesDB.has(name)) {
                    const coords = coordinatesDB.get(name)!;
                    routeCoords.push(coords);
                    validStops.push({ name: name, latlng: coords });
                    allBounds.push(coords);
                }
            });
        }

        if (routeCoords.length > 0) {
            const color = index === 0 ? '#F97316' : '#0EA5E9'; // Orange -> Blue for transfers
            const dashArray = index === 0 ? null : '10, 10';

            // Polyline
            createPolyline(L, routeCoords, {
                color, weight: 4, opacity: 0.8, dashArray
            }).addTo(layerGroup);

            // Start Marker (only for first leg)
            if (index === 0) {
                 const start = validStops[0];
                 newLayers.push(createMarker(L, start.latlng, `<b>Inicio:</b> ${escapeHtml(start.name)}`));
            }

            // End Marker (only for last leg)
            if (index === legs.length - 1) {
                 const end = validStops[validStops.length - 1];
                 newLayers.push(createMarker(L, end.latlng, `<b>Fin:</b> ${escapeHtml(end.name)}`));
            }

            // Transfer Marker (if not last leg)
            if (index < legs.length - 1) {
                const end = validStops[validStops.length - 1];
                 newLayers.push(createMarker(L, end.latlng, `<b>Transbordo:</b> ${escapeHtml(end.name)}`));
            }

            // Intermediate dots
            validStops.slice(1, -1).forEach(stop => {
                 newLayers.push(
                    createMarker(L, stop.latlng, escapeHtml(stop.name), { radius: 4, color: '#334155', fillOpacity: 1 })
                 );
            });

        } else {
            console.warn("No coordinates found for steps in this leg.");
        }
    });

    // Add all markers to the layer group
    newLayers.forEach(layer => layer.addTo(layerGroup));

    if (allBounds.length > 0) {
        map.fitBounds(allBounds, { padding: [50, 50] });
    }

    return layerGroup;
}

let loadPromise: Promise<void> | null = null;

export function loadLeaflet(): Promise<void> {
  if (typeof window === 'undefined') return Promise.resolve(); // Server-side

  // Check if Leaflet is already loaded globally
  if ((window as any).L) {
      return Promise.resolve();
  }

  // Return existing promise if loading is in progress
  if (loadPromise) return loadPromise;

  loadPromise = new Promise((resolve, reject) => {
    // 1. Load CSS
    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = '/vendor/leaflet/leaflet.css';

    // 2. Load JS
    const script = document.createElement('script');
    script.src = '/vendor/leaflet/leaflet.js';
    script.defer = true;

    const cleanup = () => {
      link.remove();
      script.remove();
    };

    const cssPromise = new Promise<void>((cssResolve, cssReject) => {
      link.onload = () => cssResolve();
      link.onerror = () => cssReject(new Error('Failed to load Leaflet CSS'));
      document.head.appendChild(link);
    });

    const jsPromise = new Promise<void>((jsResolve, jsReject) => {
      script.onload = () => {
        if ((window as any).L) {
          jsResolve();
        } else {
          jsReject(new Error('Leaflet script loaded but window.L is missing'));
        }
      };
      script.onerror = () => jsReject(new Error('Failed to load Leaflet JS'));
      document.head.appendChild(script);
    });

    Promise.all([cssPromise, jsPromise])
      .then(() => resolve())
      .catch((err) => {
        cleanup();
        loadPromise = null; // Reset on failure so we can retry
        reject(err);
      });
  });

  return loadPromise;
}
